document.addEventListener('paste', async (e) => {
  if (!document.getElementById('panel-editor').classList.contains('active')) return;
  const tag = document.activeElement?.tagName;
  if (tag === 'INPUT' || tag === 'TEXTAREA') return; // let text paste through
  const item = [...(e.clipboardData?.items || [])].find(i => i.type.startsWith('image/'));
  if (!item) return;
  e.preventDefault();
  const prev = Store.snapshotImage();
  const dataUrl = await Platform.readImageFile(item.getAsFile());
  Store.setImage(dataUrl, { source: 'clipboard' });
  if (prev) Toast.show('Image replaced', () => Store.restoreImage(prev));
});
